INSERT INTO public.products (name, name_ar, slug, description, description_ar, short_description_ar, price, currency, stock, images, category_id, meta_title, meta_description, seo_keywords, is_active, featured) VALUES ('Organic Black Seed Oil', 'زيت حبة البركة العضوي - مصدر طبيعي للقوة والصحة', 'oils-black-seed', 'Premium black seed oil rich in antioxidants, anti-inflammatory compounds, and essential fatty acids, providing numerous health benefits, including boosting immune system function, reducing inflammation and improving joint health, supporting digestive health, enhancing skin and hair health, and providing antimicrobial and antifungal properties.', 'زيت حبة البركة العضوي هو منتج طبيعي عالي الجودة، يتم استخلاصه من بذور الحبة البركة العضوية الممتازة. يتميز هذا الزيت بركيزة عالية من المضادات الحيوية والمركبات المضادة للالتهاب والحموض الدهنية الأساسية، مما يوفرมากมาย من الفوائد الصحية، بما في ذلك تعزيز função المناعة وتقليل الالتهاب وتحسين صحة المفاصل ودعم صحة الهضم وتحسين صحة الجلد والشعر.', 'زيت حبة البركة العضوي - مصدر طبيعي للقوة والصحة. يحتوي على مضادات حيوية ومركبات مضادة للالتهاب وحموض دهنية أساسية. يعزز المناعة ويقلل الالتهاب ويحسن صحة الجلد والشعر.', 220, 'MAD', 50, '{"/images/medicinal-oils/premium-black-seed-oil.png"}'::text[], 3, 'زيت حبة البركة العضوي - فوائد صحية طبيعية', 'زيت حبة البركة العضوي هو منتج طبيعي عالي الجودة يحتوي على مضادات حيوية ومركبات مضادة للالتهاب. يعزز المناعة ويقلل الالتهاب ويحسن صحة الجلد والشعر. اشتر الآن！', '{"زيت حبة البركة العضوي","زيت الحبة البركة","حبة البركة","مضادات حيوية","مركبات مضادة للالتهاب","حموض دهنية أساسية","دعم المناعة","صحة الجلد","صحة الشعر","منتجات عضويّة"}'::text[], true, true);